package ua.university.sms.service;import org.springframework.stereotype.Service;import ua.university.sms.exception.NotFoundException;import ua.university.sms.model.dto.CourseDtos.*;import ua.university.sms.model.entity.Course;import ua.university.sms.repository.*;import java.util.*;
@Service public class CourseService{private final CourseRepository repo;private final TeacherRepository teachers;public CourseService(CourseRepository r,TeacherRepository t){repo=r;teachers=t;}public Response create(Request d){Course c=new Course();apply(c,d);return dto(repo.save(c));}public Response get(Long id){return dto(find(id));}public List<Response> list(Long teacherId,Integer credits){List<Course> data=teacherId!=null?repo.findByTeacherId(teacherId):credits!=null?repo.findByCredits(credits):repo.findAll();return data.stream().map(this::dto).toList();}public Response update(Long id,Request d){Course c=find(id);apply(c,d);return dto(repo.save(c));}public void delete(Long id){repo.delete(find(id));}Course find(Long id){return repo.findById(id).orElseThrow(()->new NotFoundException("Course not found: "+id));}private void apply(Course c,Request d){c.setTitle(d.title());c.setCredits(d.credits());c.setSemester(d.semester());c.setTeacher(teachers.findById(d.teacherId()).orElseThrow(()->new NotFoundException("Teacher not found: "+d.teacherId())));}private Response dto(Course c){return new Response(c.getId(),c.getTitle(),c.getCredits(),c.getSemester(),c.getTeacher().getId(),c.getTeacher().getFullName());}}
